import type Game from "./Game";
import type * as THREE from "three";
import MapObject from "./Object";

export interface Weapon {
  // Identification & Visuals
  name?: string;
  src?: string;
  icon?: string;
  assetIcon?: string;
  sound?: string;
  shine?: number;
  transp?: boolean;
  seeThrough?: boolean;

  // Basic Weapon Flags
  melee?: boolean;
  secondary?: boolean;
  equipment?: boolean;
  bomb?: boolean;
  /**
   * true or undefined = can't aim
   * false = can aim
   */
  noAim?: boolean;
  nAuto?: boolean; // Non-automatic
  noSpread?: boolean;
  akimbo?: boolean;
  nInsp?: boolean; // No inspect
  nRing?: boolean; // No ring (visual)
  noAo?: boolean; // No Ambient Occlusion
  mysteryBoxR?: number; // Mystery box rarity tier

  // Combat Stats
  range?: number;
  rate?: number;
  ammo: number;
  reload?: number;
  dmg?: number;

  innac?: number;

  /**
   * 0 - 1 or unset if no pierce
   */
  pierce?: number;

  // Damage Dropoff
  dropStart?: number; // Distance where damage begins to drop
  dropRate?: number; // Damage lost per unit distance
  dmgDrop?: number; // Minimum damage after dropoff caps out

  // Multipliers
  hdMlt?: number; // Headshot Multiplier (Native Krunker variable)
  hsMlt?: number; // Headshot Multiplier (Legacy/Alias)
  lsMlt?: number; // Legshot Multiplier
  spdMlt?: number; // Movement speed multiplier while held
  jumpMlt?: number;
  zoom?: number; // FOV zoom factor

  // Burst Settings
  burst?: boolean;
  burstC?: number; // Burst count
  burstR?: number; // Rate between burst shots

  // Charge Settings
  chrgTime?: number;
  chrgMlt?: number;
  rateChrg?: boolean;
  ovrChrg?: boolean; // Overcharge capability
  fullChrgSht?: boolean; // Must be fully charged to shoot

  // Recoil & Recovery (Used for view math)
  recoil?: number;
  recoilR?: number;
  recoilZ?: number;
  recover?: number;
  recoverY?: number;
  recoverF?: number;
  jYMlt?: number; // Jump movement multiplier

  // Projectile Stats (Directly from weapon object)
  pj_spd?: number; // Projectile speed
  pj_grav?: number; // Gravity factor
  pj_dmg?: number;
  pj_eDmg?: number; // Explosive damage
  pj_explode?: number; // Blast radius
  pj_nImp?: boolean; // No impulse/knockback
  pj_lookDir?: boolean; // Projectile faces direction of travel

  cSpread: number[][];

  // Sub-object used by ProjectilesManager
  projectile?: {
    spd?: number;
    grav?: number;
    dmg?: number;
    range?: number;
    scale?: number;
    life?: number;
    dontPred?: boolean;
    asset?: string;
  };

  // Custom projectile rendering data generated by Krunker
  customProj?: {
    s: string;
    pjA: string | null;
    pjSp: number;
    pjG: number;
    pjSC: number;
  };

  // Physical/Misc
  physRang?: number;
  physPow?: number;
  swapTime?: number;
  aimSpd?: number;
  scale?: number;

  // View Model Offsets (Internal Use)
  xOff?: number;
  yOff?: number;
  zOff?: number;
  xOrg?: number;
  yOrg?: number;
  zOrg?: number;
  muzOff?: number;
  muzOffY?: number;
}

export interface Skin {
  ind: number;
  cnt: number;
}

